// Unsafe function exposes too much — callers must reason about safety
pub unsafe fn split_at_mut_unchecked<T>(slice: &mut [T], mid: usize) -> (&mut [T], &mut [T]) {
    let len = slice.len();
    let ptr = slice.as_mut_ptr();
    // The unsafe operations here are sound IF mid <= len
    (
        std::slice::from_raw_parts_mut(ptr, mid),
        std::slice::from_raw_parts_mut(ptr.add(mid), len - mid),
    )
}

fn main() {
    let mut v = vec![1, 2, 3, 4, 5];
    // Caller must write `unsafe` and reason about the invariant
    let (a, b) = unsafe { split_at_mut_unchecked(&mut v, 3) };
    println!("{:?} {:?}", a, b);
}

error_message:
// Compiles but has a poor API: callers must mark call sites as unsafe
// and reason about the mid <= len invariant themselves. A safe wrapper
// can check the invariant and panic on violation, just like std does.

fixed_code:
// Safe public API: checks the invariant, panics on violation
pub fn split_at_mut<T>(slice: &mut [T], mid: usize) -> (&mut [T], &mut [T]) {
    let len = slice.len();
    assert!(mid <= len, "split_at_mut index {} out of range for length {}", mid, len);
    // SAFETY: mid <= len (checked above), so both halves are within bounds
    // and non-overlapping (they start at different offsets with non-overlapping ranges).
    unsafe {
        let ptr = slice.as_mut_ptr();
        (
            std::slice::from_raw_parts_mut(ptr, mid),
            std::slice::from_raw_parts_mut(ptr.add(mid), len - mid),
        )
    }
}

fn main() {
    let mut v = vec![1, 2, 3, 4, 5];
    // No unsafe needed at the call site — the function is safe
    let (a, b) = split_at_mut(&mut v, 3);
    println!("{:?} {:?}", a, b);
    a[0] = 10;
    println!("{:?}", v);
}

