use std::ffi::CStr;

extern "C" {
    // Returns a pointer to a static C string, or NULL on error
    fn get_version() -> *const i8;
}

// BUG: doesn't check for NULL before creating CStr
pub fn version() -> &'static str {
    let ptr = unsafe { get_version() };
    // If ptr is NULL, from_ptr dereferences it — undefined behavior / segfault
    let cstr = unsafe { CStr::from_ptr(ptr) };
    cstr.to_str().unwrap()
}

fn main() {
    println!("{}", version());
}

error_message:
// No compile error. If get_version() returns NULL (e.g. on error),
// CStr::from_ptr(null) dereferences a null pointer — undefined behavior,
// likely a segfault or silent memory corruption.

fixed_code:
use std::ffi::CStr;

extern "C" {
    fn get_version() -> *const std::os::raw::c_char;
}

#[derive(Debug)]
pub enum VersionError {
    NullPointer,
    Utf8Error(std::str::Utf8Error),
}

pub fn version() -> Result<&'static str, VersionError> {
    // SAFETY: get_version() is documented to return either a valid
    // null-terminated string pointer, or NULL. We check for NULL before use.
    let ptr = unsafe { get_version() };

    if ptr.is_null() {
        return Err(VersionError::NullPointer);
    }

    // SAFETY: ptr is non-null (checked above) and points to a
    // null-terminated C string valid for 'static lifetime (documented).
    let cstr = unsafe { CStr::from_ptr(ptr) };
    cstr.to_str().map_err(VersionError::Utf8Error)
}

fn main() {
    // Simulating with a known-safe pointer for the example
    match version() {
        Ok(v) => println!("version: {}", v),
        Err(e) => println!("error: {:?}", e),
    }
}

