pub struct SafeSlice {
    ptr: *const i32,
    len: usize,
}

impl SafeSlice {
    pub fn new(slice: &[i32]) -> Self {
        SafeSlice { ptr: slice.as_ptr(), len: slice.len() }
    }

    pub fn get(&self, idx: usize) -> Option<&i32> {
        if idx >= self.len {
            return None;
        }
        // SAFETY: idx < self.len, ptr is valid for self.len elements
        unsafe { Some(&*self.ptr.add(idx)) }
    }
}

fn main() {
    let data = vec![10, 20, 30];
    let s = SafeSlice::new(&data);
    drop(data);  // BUG: data freed, but SafeSlice still holds ptr to freed memory
    println!("{:?}", s.get(0));  // use-after-free — UB!
}

error_message:
// No compile error (the lifetime issue is hidden by the raw pointer).
// Clippy warns: "unsound: raw pointer derived from reference must not outlive it"
// The safe abstraction is actually UNSOUND: the lifetime of SafeSlice is not
// tied to the lifetime of the slice it was built from.

fixed_code:
// Correct: tie the lifetime of SafeSlice to the slice it borrows
pub struct SafeSlice<'a> {
    inner: &'a [i32],  // just use a slice reference — no unsafe needed!
}

impl<'a> SafeSlice<'a> {
    pub fn new(slice: &'a [i32]) -> Self {
        SafeSlice { inner: slice }
    }

    pub fn get(&self, idx: usize) -> Option<&i32> {
        self.inner.get(idx)  // no unsafe needed
    }

    pub fn len(&self) -> usize {
        self.inner.len()
    }
}

// If you genuinely need unsafe (e.g. for a custom allocator wrapper):
pub struct RawSlice<'a> {
    ptr: *const i32,
    len: usize,
    // PhantomData ties the lifetime to the original data,
    // preventing use-after-free at compile time
    _marker: std::marker::PhantomData<&'a i32>,
}

fn main() {
    let data = vec![10, 20, 30];
    let s = SafeSlice::new(&data);
    // drop(data);  // compile error: cannot move `data` because it is borrowed
    println!("{:?}", s.get(0));
}

