// No compile error. Issues:
// 1. No SAFETY comment explaining why the unsafe block is sound
// 2. The unsafe block is sound for valid fds, but the function doesn't
//    document what "fd" must be (open, valid, readable)
// 3. If buf.len() is 0, the result could be misinterpreted
// 4. Missing SAFETY for the platform-specific cast from *mut u8 to *mut c_void

fixed_code:
use std::io;

/// Read up to `buf.len()` bytes from the given file descriptor into `buf`.
///
/// # Safety (for callers of the *hypothetical* unsafe version)
/// Here we wrap the unsafe syscall in a safe API:
/// - `fd` must be a valid, open, and readable file descriptor for the
///   lifetime of this call.
/// - This is an OS-level constraint we cannot check in safe Rust,
///   but passing an invalid fd causes an OS error (EBADF), not UB.
pub fn read_into(fd: i32, buf: &mut [u8]) -> io::Result<usize> {
    if buf.is_empty() {
        return Ok(0);
    }

    // SAFETY:
    // - `buf.as_mut_ptr()` is valid for `buf.len()` bytes (guaranteed by &mut [u8]).
    // - `*mut c_void` cast is valid on all platforms where u8 and c_void have
    //   compatible representation (all POSIX-compatible systems).
    // - We pass `buf.len()` as the count, so no out-of-bounds write can occur.
    // - An invalid `fd` results in an OS error (errno EBADF), not memory unsafety.
    let result = unsafe {
        libc::read(
            fd,
            buf.as_mut_ptr() as *mut libc::c_void,
            buf.len(),
        )
    };

    if result < 0 {
        Err(io::Error::last_os_error())
    } else {
        // SAFETY: result is non-negative and libc::read returns
        // at most buf.len() bytes, which fits in usize on any platform.
        Ok(result as usize)
    }
}

fn main() {
    let mut buf = [0u8; 64];
    match read_into(0, &mut buf) {  // fd 0 = stdin
        Ok(n) => println!("read {} bytes", n),
        Err(e) => println!("error: {}", e),
    }
}

