// Compiles. But if a caller holds a &mut T from peek_front_mut() and then
// calls push() through a separate path (e.g. via Rc<RefCell<RingBuffer>>),
// two &mut T references to the same slot could coexist — aliased mutable
// references are undefined behavior.

fixed_code:
use std::mem::MaybeUninit;

struct RingBuffer<T, const N: usize> {
    data: [MaybeUninit<T>; N],
    head: usize,
    tail: usize,
    len: usize,
}

impl<T, const N: usize> RingBuffer<T, N> {
    fn new() -> Self {
        RingBuffer {
            // SAFETY: MaybeUninit array doesn't need initialisation
            data: unsafe { MaybeUninit::uninit().assume_init() },
            head: 0, tail: 0, len: 0,
        }
    }

    fn push(&mut self, val: T) -> bool {
        if self.len == N { return false; }
        self.data[self.tail].write(val);
        self.tail = (self.tail + 1) % N;
        self.len += 1;
        true
    }

    fn pop(&mut self) -> Option<T> {
        if self.len == 0 { return None; }
        // SAFETY: head slot is initialised (len > 0), and we won't read it again
        // (head advances, len decrements — the slot is logically consumed).
        let val = unsafe { self.data[self.head].assume_init_read() };
        self.head = (self.head + 1) % N;
        self.len -= 1;
        Some(val)
    }

    // Safe read-only peek: returns shared reference, no aliasing possible
    fn peek_front(&self) -> Option<&T> {
        if self.len == 0 { return None; }
        // SAFETY: head slot is initialised (len > 0).
        // &self ensures no concurrent mutation.
        Some(unsafe { self.data[self.head].assume_init_ref() })
    }

    fn len(&self) -> usize { self.len }
}

fn main() {
    let mut buf: RingBuffer<i32, 4> = RingBuffer::new();
    buf.push(1); buf.push(2); buf.push(3);
    println!("front: {:?}", buf.peek_front());
    println!("pop: {:?}", buf.pop());
    println!("len: {}", buf.len());
}
